import injector from 'vue-inject'

const ContextMenuService = {
  stringMenus (column, rowData) {
    return [
      Object.assign({}, column, { conditionText: 'equals', rule: { term: column.field, condition: '=', value: `'${rowData[column.field]}'` } }),
      Object.assign({}, column, { conditionText: 'does not equal', rule: { term: column.field, condition: '<>', value: `'${rowData[column.field]}'` } })
    ]
  },

  integerMenus (column, rowData) {
    return [
      Object.assign({}, column, { conditionText: 'equals', rule: { term: column.field, condition: '=', value: rowData[column.field] } }),
      Object.assign({}, column, { conditionText: 'does not equal', rule: { term: column.field, condition: '<>', value: rowData[column.field] } }),
      Object.assign({}, column, { conditionText: 'less than', rule: { term: column.field, condition: '<', value: rowData[column.field] } }),
      Object.assign({}, column, { conditionText: 'greater than', rule: { term: column.field, condition: '>', value: rowData[column.field] } })
    ]
  }
}

injector.service('ContextMenuService', () => {
  return ContextMenuService
})



