import Vue from 'vue'
import VueRouter from 'vue-router'
import * as componentExports from './utilities/vue-file-loader'

// define pages to import and use on a specific route
const {
  home,
  timeline
} = componentExports.exports

Vue.use(VueRouter)

const routes = [
  { name: 'home', path: '/', component: home },
  { name: 'timeline', path: '/timeline/:id', component: timeline }
]

export default new VueRouter({
  routes
})



