<template>
  <div class="select-rule-container">
    <div class="row">
      <div class="col-xs-12 text-right">
        <div class="form-check">
          <label class="form-check-label">
            <input type="checkbox" class="form-check-input" v-model="isSimple" @change="updateIsSimple">
            Simple Comparison
          </label>
        </div>
      </div>
    </div>
    <div class="row" v-show="!isSimple">
      <div class="col-md-4 col-sm-12 tight-gutter">
        <div class="form-group">
          <label :for="rule.term">Term</label>

          <autocomplete
            ref="autocomplete"
            :source="columns"
            v-model="rule.term"
            :initial-value="rule.term"
            input-class="form-control"
            :results-display="formattedAutocomplete"
            results-property="field"
            results-value="field">
          </autocomplete>
        </div>
        
      </div>
      <div class="col-md-3 col-sm-12 tight-gutter">
        <div class="form-group">
          <label :for="rule.condition">Condition</label>
          <input v-model="rule.condition" class="form-control"/>
        </div>
      </div>
      <div class="col-md-4 col-sm-12 tight-gutter">
        <div class="form-group">
          <label :for="rule.value">Value</label>
          <input v-model="rule.value" class="form-control"/>
        </div>
      </div>
      <div class="col-md-1 col-sm-12 tight-gutter">
        <button class="delete-btn" @click="removeRule">
          <i class="fa fa-trash-o"></i>
        </button>
      </div>
    </div>

    <div class="row" v-show="isSimple">
      <div class="col-xs-12 tight-gutter">
        <div class="form-group">
          <label :for="rule.term">Term</label>

          <multiselect
            ref="expressionSelect"
            v-model="selectedColumns"
            tag-placeholder="Add new selection"
            placeholder="Search or add a selection"
            track-by="search"
            :options="columns"
            :multiple="true"
            :taggable="true"
            :showLabels="false"
            :custom-label="columnLabel"
            :close-on-select="false"
            :clear-on-select="true"
            @tag="addTag">
          </multiselect>
        </div>
      </div>
    </div>
    <div class="row label-or" v-show="!last">
      <div class="col-md-12 text-center">
        <span class="label label-primary">Or</span>
      </div>
    </div>
  </div>
</template>

<script>
import Autocomplete from 'vuejs-auto-complete'
import Multiselect from 'vue-multiselect'

export default {
  name: 'SelectRule',
  props: ['rule', 'last', 'id'],
  data: () => {
    return {
      indexer: 0,
      isSimple: false,
      selectedColumns: []
    }
  },
  created () {
    if (!this.rule.term && !this.rule.condition && this.rule.value) {
      this.isSimple = true
    }

    if (this.rule.value) {
      var self = this
      var value = this.rule.value + ''
      value.split(' ').forEach(x => self.addTag(x))
    }
  },
  components: {
    Autocomplete,
    Multiselect
  },
  computed: {
    columns () {
      return this.$store.getters[`timelineModule${this.id}/columns`].map(c => {
        // add additional fields for multiselect dropdown
        c['code'] = c.field
        c['search'] = `${c.name} ${c.field}`
        return c
      })
    }
  },
  watch: {
    columns () {
      this.setPredefinedValue()
    },
    selectedColumns (selected) {
      var self = this
      // multiselect filters based on a tracked id.
      // to have the ability to add multiple of one item we need to update the tracked id.
      selected = selected.map(s => {
        s.search = s.search + '.' + self.indexer++
        return s
      })

      if (self.rule) {
        // this updates the model value
        self.rule.value = selected.map(s => {
          return s.code
        }).join(' ')
      }
    }
  },
  mounted () {
    this.setPredefinedValue()
  },
  methods: {
    addTag (newTag) {
      const tag = {
        name: newTag,
        code: newTag,
        typed: true
      }
      this.selectedColumns.push(tag)
    },
    columnLabel (col) {
      return col.typed ? `${col.name}` : `${col.name} - ${col.code}`
    },
    formattedAutocomplete (result) {
      return result.name + ' [' + result.field + ']'
    },
    removeRule () {
      this.$emit('removeRule', this.rule)
    },
    setPredefinedValue () {
      var self = this
      this.$nextTick(() => {
        if (self.rule.term && self.columns.length > 0) {
          var value = self.$refs.autocomplete.source.filter((item) => {
            return item.field === self.rule.term
          })

          if (value) {
            self.$refs.autocomplete.setValues(value[0])
          }
        }
      })
    },
    updateIsSimple () {
      if (this.isSimple && (this.rule.term && this.rule.condition)) {
        this.rule.term = ''
        this.rule.condition = ''
      }
    }
  }
}
</script>

<style scoped>
  .tight-gutter:not(:first-of-type) {
    padding-left: 4px;
  }
  .tight-gutter:not(:last-of-type) {
    padding-right: 4px;
  }
  .delete-btn {
    margin-top: 29px;
  }

  .label-or {
    margin-top: 10px;
    margin-bottom: 20px;
  }
  .label-or span {
    padding: 10px;
  }
  .btn-add-or {
    margin-top: 12px;
  }
</style>


