import SelectRule from './selectRuleModel'

var generateId = () => {
  // Math.random should be unique because of its seeding algorithm.
  // Convert it to base 36 (numbers + letters), and grab the first 9 characters
  // after the decimal.
  return '_' + Math.random().toString(36).substr(2, 9)
}

export default class Select {
  constructor () {
    this.id = 0
    this.op = 'Select'
    this.data = {
      rules: []
    }
  }

  createFromSource (select) {
    return Object.assign(this, select)
  }

  addRule (incomingRule) {
    var rule = incomingRule ? new SelectRule().createFromSource(incomingRule) : new SelectRule()
    rule.id = generateId()

    if (this.data) {
      this.data.rules.push(rule)
    }

    return rule
  }

  removeRule (rule) {
    this.data.rules = this.data.rules.filter(r => {
      return r.id !== rule.id
    })
  }
}



